import { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import API, { getApiError } from "../services/api";
import { getDefaultRouteForRole, setSession } from "../services/auth";

function normalizeEmail(email) {
  return email.trim().toLowerCase();
}

export default function Login() {
  const navigate = useNavigate();
  const location = useLocation();
  const redirectTo = location.state?.from;
  const [form, setForm] = useState({ email: "", password: "" });
  const [recoveryForm, setRecoveryForm] = useState({
    identifier: "",
    channel: "email",
    otp: "",
    newPassword: ""
  });
  const [mode, setMode] = useState("login");
  const [otpRequested, setOtpRequested] = useState(false);
  const [loading, setLoading] = useState(false);
  const [recoveryLoading, setRecoveryLoading] = useState(false);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [debugOtp, setDebugOtp] = useState("");

  const updateField = (key, value) => {
    setForm((current) => ({ ...current, [key]: value }));
  };

  const updateRecoveryField = (key, value) => {
    setRecoveryForm((current) => ({ ...current, [key]: value }));
  };

  const resetRecoveryState = () => {
    setOtpRequested(false);
    setRecoveryForm({
      identifier: "",
      channel: "email",
      otp: "",
      newPassword: ""
    });
    setDebugOtp("");
    setError("");
    setMessage("");
  };

  const completeLogin = (response) => {
    setSession(response.data.token, response.data.user);
    navigate(redirectTo || getDefaultRouteForRole(response.data.user?.role), {
      replace: true
    });
  };

  const handleLogin = async (event) => {
    event.preventDefault();
    setError("");
    setMessage("");
    setLoading(true);

    const credentials = {
      email: normalizeEmail(form.email),
      password: form.password
    };

    try {
      const response = await API.post("/login", credentials);
      completeLogin(response);
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to log in."));
    } finally {
      setLoading(false);
    }
  };

  const handleRequestOtp = async (event) => {
    event.preventDefault();
    setError("");
    setMessage("");
    setDebugOtp("");
    setRecoveryLoading(true);

    try {
      const response = await API.post("/forgot-password/request-otp", {
        identifier: recoveryForm.identifier,
        channel: recoveryForm.channel
      });

      setOtpRequested(true);
      setMessage(response.data.message);
      setDebugOtp(response.data.debugOtp || "");
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to send OTP."));
    } finally {
      setRecoveryLoading(false);
    }
  };

  const handleResetPassword = async (event) => {
    event.preventDefault();
    setError("");
    setMessage("");
    setRecoveryLoading(true);

    try {
      const response = await API.post("/forgot-password/reset", {
        identifier: recoveryForm.identifier,
        otp: recoveryForm.otp,
        newPassword: recoveryForm.newPassword
      });

      setMessage(response.data.message);
      setMode("login");
      setOtpRequested(false);
      setDebugOtp("");
      setForm((current) => ({
        ...current,
        email:
          recoveryForm.channel === "email"
            ? normalizeEmail(recoveryForm.identifier)
            : current.email,
        password: ""
      }));
      setRecoveryForm((current) => ({
        ...current,
        otp: "",
        newPassword: ""
      }));
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to reset password."));
    } finally {
      setRecoveryLoading(false);
    }
  };

  return (
    <div className="auth-layout">
      <section className="auth-hero">
        <span className="eyebrow">Gym membership manager</span>
        <h1>Run your front desk from one clean workspace.</h1>
        <p>Track members, renewals, and attendance in one place.</p>

        <div className="auth-feature-list">
          <div className="auth-feature">
            <strong>Membership tracking</strong>
            <span>View members and plans quickly.</span>
          </div>
          <div className="auth-feature">
            <strong>Attendance updates</strong>
            <span>Mark check-ins fast.</span>
          </div>
          <div className="auth-feature">
            <strong>Renewal alerts</strong>
            <span>See renewals early.</span>
          </div>
        </div>
      </section>

      <section className="auth-card">
        <div>
          <span className="eyebrow">
            {mode === "login" ? "Welcome back" : "Account recovery"}
          </span>
          <h2>{mode === "login" ? "Sign in to fitLedger" : "Reset your password"}</h2>
          <p className="muted-copy">
            {mode === "login"
              ? "Sign in with your registered email and password."
              : "Request an OTP by email or mobile number, then set a new password."}
          </p>
          <p className="muted-copy">
            The backend uses `MONGO_URI` when available, otherwise local MongoDB on `127.0.0.1:27017`.
          </p>
          <p className="muted-copy">
            For a brand-new database, create the first admin with `POST /api/setup/admin`.
          </p>
        </div>

        {message ? <div className="status-banner">{message}</div> : null}
        {error ? <div className="status-banner status-banner--error">{error}</div> : null}
        {debugOtp ? (
          <div className="status-banner">
            Development OTP preview: <strong>{debugOtp}</strong>
          </div>
        ) : null}

        {mode === "login" ? (
          <form className="auth-form" onSubmit={handleLogin}>
            <label className="field">
              <span>Email</span>
              <input
                type="email"
                placeholder="owner@example.com"
                value={form.email}
                onChange={(event) => updateField("email", event.target.value)}
              />
            </label>

            <label className="field">
              <span>Password</span>
              <input
                type="password"
                placeholder="Enter your password"
                value={form.password}
                onChange={(event) => updateField("password", event.target.value)}
              />
            </label>

            <div className="auth-actions">
              <button className="button" type="submit" disabled={loading}>
                {loading ? "Signing in..." : "Login"}
              </button>
              <button
                className="button button--ghost"
                type="button"
                onClick={() => {
                  setMode("forgot");
                  resetRecoveryState();
                }}
              >
                Forgot password
              </button>
            </div>
          </form>
        ) : (
          <form
            className="auth-form"
            onSubmit={otpRequested ? handleResetPassword : handleRequestOtp}
          >
            <label className="field">
              <span>Send OTP By</span>
              <select
                value={recoveryForm.channel}
                onChange={(event) => updateRecoveryField("channel", event.target.value)}
                disabled={otpRequested}
              >
                <option value="email">Email</option>
                <option value="phone">Mobile number</option>
              </select>
            </label>

            <label className="field">
              <span>{recoveryForm.channel === "email" ? "Email" : "Mobile number"}</span>
              <input
                type={recoveryForm.channel === "email" ? "email" : "tel"}
                placeholder={
                  recoveryForm.channel === "email" ? "owner@example.com" : "9876543210"
                }
                value={recoveryForm.identifier}
                onChange={(event) => updateRecoveryField("identifier", event.target.value)}
                disabled={otpRequested}
              />
            </label>

            {otpRequested ? (
              <>
                <label className="field">
                  <span>OTP</span>
                  <input
                    placeholder="Enter the 6-digit OTP"
                    value={recoveryForm.otp}
                    onChange={(event) => updateRecoveryField("otp", event.target.value)}
                  />
                </label>

                <label className="field">
                  <span>New password</span>
                  <input
                    type="password"
                    placeholder="Enter a new password"
                    value={recoveryForm.newPassword}
                    onChange={(event) =>
                      updateRecoveryField("newPassword", event.target.value)
                    }
                  />
                </label>
              </>
            ) : null}

            <div className="auth-actions">
              <button className="button" type="submit" disabled={recoveryLoading}>
                {recoveryLoading
                  ? otpRequested
                    ? "Resetting..."
                    : "Sending OTP..."
                  : otpRequested
                    ? "Reset password"
                    : "Send OTP"}
              </button>
              <button
                className="button button--ghost"
                type="button"
                onClick={() => {
                  setMode("login");
                  resetRecoveryState();
                }}
              >
                Back to login
              </button>
            </div>
          </form>
        )}
      </section>
    </div>
  );
}
